8858       if (SrcIt != MinBWs.end()) {
8859         SrcBWSz = SrcIt->second.first;
8860         SrcScalarTy = IntegerType::get(F->getContext(), SrcBWSz);
8861         SrcVecTy = FixedVectorType::get(SrcScalarTy, VL.size());
8862       }
8863       unsigned BWSz = DL->getTypeSizeInBits(ScalarTy);
8864       if (BWSz == SrcBWSz) {
8865         VecOpcode = Instruction::BitCast;
8866       } else if (BWSz < SrcBWSz) {
8867         VecOpcode = Instruction::Trunc;
8868       } else if (It != MinBWs.end()) {
8869         assert(BWSz > SrcBWSz && "Invalid cast!");
8870         VecOpcode = It->second.second ? Instruction::SExt : Instruction::ZExt;
8871       } else if (SrcIt != MinBWs.end()) {
8872         assert(BWSz > SrcBWSz && "Invalid cast!");
8873         VecOpcode =
8874             SrcIt->second.second ? Instruction::SExt : Instruction::ZExt;
8875       }
8876     }
8877     auto GetScalarCost = [&](unsigned Idx) -> InstructionCost {
8878       auto *VI = cast<Instruction>(UniqueValues[Idx]);
8879       return TTI->getCastInstrCost(Opcode, VL0->getType(),
8880                                    VL0->getOperand(0)->getType(),
8881                                    TTI::getCastContextHint(VI), CostKind, VI);
8882     };
8883     auto GetVectorCost = [=](InstructionCost CommonCost) {
8884       // Do not count cost here if minimum bitwidth is in effect and it is just
8885       // a bitcast (here it is just a noop).
8886       if (VecOpcode != Opcode && VecOpcode == Instruction::BitCast)
8887         return CommonCost;
8888       auto *VI = VL0->getOpcode() == Opcode ? VL0 : nullptr;
8889       TTI::CastContextHint CCH = GetCastContextHint(VL0->getOperand(0));
8890       return CommonCost +
8891              TTI->getCastInstrCost(VecOpcode, VecTy, SrcVecTy, CCH, CostKind,
8892                                    VecOpcode == Opcode ? VI : nullptr);
8893     };
8894     return GetCostDiff(GetScalarCost, GetVectorCost);
8895   }
8896   case Instruction::FCmp:
8897   case Instruction::ICmp:
8898   case Instruction::Select: {
8899     CmpInst::Predicate VecPred, SwappedVecPred;
8900     auto MatchCmp = m_Cmp(VecPred, m_Value(), m_Value());
8901     if (match(VL0, m_Select(MatchCmp, m_Value(), m_Value())) ||
8902         match(VL0, MatchCmp))
8903       SwappedVecPred = CmpInst::getSwappedPredicate(VecPred);
8904     else
8905       SwappedVecPred = VecPred = ScalarTy->isFloatingPointTy()
8906                                      ? CmpInst::BAD_FCMP_PREDICATE
8907                                      : CmpInst::BAD_ICMP_PREDICATE;
8908     auto GetScalarCost = [&](unsigned Idx) {
8909       auto *VI = cast<Instruction>(UniqueValues[Idx]);
8910       CmpInst::Predicate CurrentPred = ScalarTy->isFloatingPointTy()
8911                                            ? CmpInst::BAD_FCMP_PREDICATE
8912                                            : CmpInst::BAD_ICMP_PREDICATE;
8913       auto MatchCmp = m_Cmp(CurrentPred, m_Value(), m_Value());
8914       if ((!match(VI, m_Select(MatchCmp, m_Value(), m_Value())) &&
8915            !match(VI, MatchCmp)) ||
8916           (CurrentPred != VecPred && CurrentPred != SwappedVecPred))
8917         VecPred = SwappedVecPred = ScalarTy->isFloatingPointTy()
8918                                        ? CmpInst::BAD_FCMP_PREDICATE
8919                                        : CmpInst::BAD_ICMP_PREDICATE;
8920 
8921       return TTI->getCmpSelInstrCost(E->getOpcode(), OrigScalarTy,
8922                                      Builder.getInt1Ty(), CurrentPred, CostKind,
8923                                      VI);
8924     };
8925     auto GetVectorCost = [&](InstructionCost CommonCost) {
8926       auto *MaskTy = FixedVectorType::get(Builder.getInt1Ty(), VL.size());
8927 
8928       InstructionCost VecCost = TTI->getCmpSelInstrCost(
8929           E->getOpcode(), VecTy, MaskTy, VecPred, CostKind, VL0);
8930       // Check if it is possible and profitable to use min/max for selects
8931       // in VL.
8932       //
8933       auto IntrinsicAndUse = canConvertToMinOrMaxIntrinsic(VL);
8934       if (IntrinsicAndUse.first != Intrinsic::not_intrinsic) {
8935         IntrinsicCostAttributes CostAttrs(IntrinsicAndUse.first, VecTy,
8936                                           {VecTy, VecTy});
8937         InstructionCost IntrinsicCost =
8938             TTI->getIntrinsicInstrCost(CostAttrs, CostKind);
8939         // If the selects are the only uses of the compares, they will be
8940         // dead and we can adjust the cost by removing their cost.
8941         if (IntrinsicAndUse.second)
8942           IntrinsicCost -= TTI->getCmpSelInstrCost(Instruction::ICmp, VecTy,
8943                                                    MaskTy, VecPred, CostKind);
8944         VecCost = std::min(VecCost, IntrinsicCost);
8945       }
8946       return VecCost + CommonCost;
8947     };
8948     return GetCostDiff(GetScalarCost, GetVectorCost);
8949   }
8950   case Instruction::FNeg:
8951   case Instruction::Add:
8952   case Instruction::FAdd:
8953   case Instruction::Sub:
8954   case Instruction::FSub:
8955   case Instruction::Mul:
8956   case Instruction::FMul:
8957   case Instruction::UDiv:
8958   case Instruction::SDiv:
8959   case Instruction::FDiv:
8960   case Instruction::URem:
8961   case Instruction::SRem:
8962   case Instruction::FRem:
8963   case Instruction::Shl:
8964   case Instruction::LShr:
8965   case Instruction::AShr:
8966   case Instruction::And:
8967   case Instruction::Or:
8968   case Instruction::Xor: {
8969     auto GetScalarCost = [&](unsigned Idx) {
8970       auto *VI = cast<Instruction>(UniqueValues[Idx]);
8971       unsigned OpIdx = isa<UnaryOperator>(VI) ? 0 : 1;
8972       TTI::OperandValueInfo Op1Info = TTI::getOperandInfo(VI->getOperand(0));
8973       TTI::OperandValueInfo Op2Info =
8974           TTI::getOperandInfo(VI->getOperand(OpIdx));
8975       SmallVector<const Value *> Operands(VI->operand_values());
8976       return TTI->getArithmeticInstrCost(ShuffleOrOp, OrigScalarTy, CostKind,
8977                                          Op1Info, Op2Info, Operands, VI);
8978     };
8979     auto GetVectorCost = [=](InstructionCost CommonCost) {
8980       unsigned OpIdx = isa<UnaryOperator>(VL0) ? 0 : 1;
8981       TTI::OperandValueInfo Op1Info = getOperandInfo(E->getOperand(0));
8982       TTI::OperandValueInfo Op2Info = getOperandInfo(E->getOperand(OpIdx));
8983       return TTI->getArithmeticInstrCost(ShuffleOrOp, VecTy, CostKind, Op1Info,
8984                                          Op2Info, std::nullopt, nullptr, TLI) +
8985              CommonCost;
8986     };
8987     return GetCostDiff(GetScalarCost, GetVectorCost);
8988   }
8989   case Instruction::GetElementPtr: {
8990     return CommonCost + GetGEPCostDiff(VL, VL0);
8991   }
8992   case Instruction::Load: {
8993     auto GetScalarCost = [&](unsigned Idx) {
8994       auto *VI = cast<LoadInst>(UniqueValues[Idx]);
8995       return TTI->getMemoryOpCost(Instruction::Load, OrigScalarTy,
8996                                   VI->getAlign(), VI->getPointerAddressSpace(),
8997                                   CostKind, TTI::OperandValueInfo(), VI);
8998     };
8999     auto *LI0 = cast<LoadInst>(VL0);
9000     auto GetVectorCost = [&](InstructionCost CommonCost) {
9001       InstructionCost VecLdCost;
9002       if (E->State == TreeEntry::Vectorize) {
9003         VecLdCost = TTI->getMemoryOpCost(
9004             Instruction::Load, VecTy, LI0->getAlign(),
9005             LI0->getPointerAddressSpace(), CostKind, TTI::OperandValueInfo());
9006       } else if (E->State == TreeEntry::StridedVectorize) {
9007         Align CommonAlignment =
9008             computeCommonAlignment<LoadInst>(UniqueValues.getArrayRef());
9009         VecLdCost = TTI->getStridedMemoryOpCost(
9010             Instruction::Load, VecTy, LI0->getPointerOperand(),
9011             /*VariableMask=*/false, CommonAlignment, CostKind);
9012       } else {
9013         assert(E->State == TreeEntry::ScatterVectorize && "Unknown EntryState");
9014         Align CommonAlignment =
9015             computeCommonAlignment<LoadInst>(UniqueValues.getArrayRef());
9016         VecLdCost = TTI->getGatherScatterOpCost(
9017             Instruction::Load, VecTy, LI0->getPointerOperand(),
9018             /*VariableMask=*/false, CommonAlignment, CostKind);
9019       }
9020       return VecLdCost + CommonCost;
9021     };
9022 
9023     InstructionCost Cost = GetCostDiff(GetScalarCost, GetVectorCost);
9024     // If this node generates masked gather load then it is not a terminal node.
9025     // Hence address operand cost is estimated separately.
9026     if (E->State == TreeEntry::ScatterVectorize)
9027       return Cost;
9028 
9029     // Estimate cost of GEPs since this tree node is a terminator.
9030     SmallVector<Value *> PointerOps(VL.size());
9031     for (auto [I, V] : enumerate(VL))
9032       PointerOps[I] = cast<LoadInst>(V)->getPointerOperand();
9033     return Cost + GetGEPCostDiff(PointerOps, LI0->getPointerOperand());
9034   }
9035   case Instruction::Store: {
9036     bool IsReorder = !E->ReorderIndices.empty();
9037     auto GetScalarCost = [=](unsigned Idx) {
9038       auto *VI = cast<StoreInst>(VL[Idx]);
9039       TTI::OperandValueInfo OpInfo = TTI::getOperandInfo(VI->getValueOperand());
9040       return TTI->getMemoryOpCost(Instruction::Store, OrigScalarTy,
9041                                   VI->getAlign(), VI->getPointerAddressSpace(),
9042                                   CostKind, OpInfo, VI);
9043     };
9044     auto *BaseSI =
9045         cast<StoreInst>(IsReorder ? VL[E->ReorderIndices.front()] : VL0);
9046     auto GetVectorCost = [=](InstructionCost CommonCost) {
9047       // We know that we can merge the stores. Calculate the cost.
9048       TTI::OperandValueInfo OpInfo = getOperandInfo(E->getOperand(0));
9049       return TTI->getMemoryOpCost(Instruction::Store, VecTy, BaseSI->getAlign(),
9050                                   BaseSI->getPointerAddressSpace(), CostKind,
9051                                   OpInfo) +
9052              CommonCost;
9053     };
9054     SmallVector<Value *> PointerOps(VL.size());
9055     for (auto [I, V] : enumerate(VL)) {
9056       unsigned Idx = IsReorder ? E->ReorderIndices[I] : I;
9057       PointerOps[Idx] = cast<StoreInst>(V)->getPointerOperand();
9058     }
9059 
9060     return GetCostDiff(GetScalarCost, GetVectorCost) +
9061            GetGEPCostDiff(PointerOps, BaseSI->getPointerOperand());
9062   }
9063   case Instruction::Call: {
9064     auto GetScalarCost = [&](unsigned Idx) {
9065       auto *CI = cast<CallInst>(UniqueValues[Idx]);
9066       Intrinsic::ID ID = getVectorIntrinsicIDForCall(CI, TLI);
9067       if (ID != Intrinsic::not_intrinsic) {
9068         IntrinsicCostAttributes CostAttrs(ID, *CI, 1);
9069         return TTI->getIntrinsicInstrCost(CostAttrs, CostKind);
9070       }
9071       return TTI->getCallInstrCost(CI->getCalledFunction(),
9072                                    CI->getFunctionType()->getReturnType(),
9073                                    CI->getFunctionType()->params(), CostKind);
9074     };
9075     auto GetVectorCost = [=](InstructionCost CommonCost) {
9076       auto *CI = cast<CallInst>(VL0);
9077       auto VecCallCosts = getVectorCallCosts(CI, VecTy, TTI, TLI);
9078       return std::min(VecCallCosts.first, VecCallCosts.second) + CommonCost;
9079     };
9080     return GetCostDiff(GetScalarCost, GetVectorCost);
9081   }
9082   case Instruction::ShuffleVector: {
9083     assert(E->isAltShuffle() &&
9084            ((Instruction::isBinaryOp(E->getOpcode()) &&
9085              Instruction::isBinaryOp(E->getAltOpcode())) ||
9086             (Instruction::isCast(E->getOpcode()) &&
9087              Instruction::isCast(E->getAltOpcode())) ||
9088             (isa<CmpInst>(VL0) && isa<CmpInst>(E->getAltOp()))) &&
9089            "Invalid Shuffle Vector Operand");
